const response = $json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text;

if (!text) {
  const videoId = $('Filter Recent Videos').item.json.video_id;
  throw new Error(`No Gemini response for video: ${videoId}`);
}

let analysis;
try {
  analysis = JSON.parse(text);
} catch (e) {
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  analysis = JSON.parse(cleaned);
}

const video = $('Filter Recent Videos').item.json;

return [{
  json: {
    video_id: video.video_id,
    video_url: video.video_url,
    video_title: video.video_title,
    channel_id: video.channel_id,
    channel_name: video.channel_name,
    pub_date: video.pub_date,
    speaker_name: analysis.speaker_name || 'Unknown Speaker',
    speaker_title: analysis.speaker_title || '',
    top_quotes: analysis.top_quotes || [],
    key_insights: analysis.key_insights || [],
    narrative_summary: analysis.narrative_summary || '',
    surprising_statement: analysis.surprising_statement || ''
  }
}];

